import 'package:flutter_riverpod/flutter_riverpod.dart'; import '../../../../models/product_model.dart'; final invoiceProvider = StateNotifierProvider<InvoiceNotifier, InvoiceState>((ref)=>InvoiceNotifier());
class InvoiceItem { final Product product; int quantity; double unitPrice; InvoiceItem({required this.product, this.quantity=1}) : unitPrice = product.unitPrice; }
class InvoiceState { final List<InvoiceItem> items; final double discount; final double taxRate; InvoiceState({this.items=const[], this.discount=0, this.taxRate=0.15}); double get subtotal => items.fold(0, (s,i)=>s+(i.unitPrice*i.quantity)); double get taxAmount => (subtotal-discount)*taxRate; double get finalTotal => subtotal-discount+taxAmount; InvoiceState copyWith({List<InvoiceItem>? items, double? discount}) => InvoiceState(items: items??this.items, discount: discount??this.discount); }
class InvoiceNotifier extends StateNotifier<InvoiceState> { InvoiceNotifier() : super(InvoiceState()); void addProduct(Product p) { final idx = state.items.indexWhere((i)=>i.product.sku==p.sku); if(idx!=-1) { final newItems = [...state.items]; newItems[idx].quantity++; state = state.copyWith(items: newItems); } else { state = state.copyWith(items: [...state.items, InvoiceItem(product: p)]); } } void removeItem(int idx) { final newItems = [...state.items]..removeAt(idx); state = state.copyWith(items: newItems); } void incrementQuantity(int idx) { final newItems = [...state.items]; newItems[idx].quantity++; state = state.copyWith(items: newItems); } void decrementQuantity(int idx) { final newItems = [...state.items]; if(newItems[idx].quantity>1) newItems[idx].quantity--; state = state.copyWith(items: newItems); } void setDiscount(double d) => state = state.copyWith(discount: d); }
